<div class="stats-grid"><article class="stat-card"><span>Cliques totais</span><strong><?= (int) ($summary['totals']['clicks'] ?? 0) ?></strong></article><article class="stat-card"><span>WhatsApp</span><strong><?= (int) ($summary['totals']['whatsapp'] ?? 0) ?></strong></article><article class="stat-card"><span>Reservas</span><strong><?= (int) ($summary['totals']['reservations'] ?? 0) ?></strong></article><article class="stat-card"><span>Page views</span><strong><?= (int) ($summary['totals']['page_views'] ?? 0) ?></strong></article></div><div class="admin-grid"><?php foreach ($summary['rankings'] as $label => $rows): ?><section class="panel"><h2><?= htmlspecialchars(ucfirst($label)) ?></h2><div class="table-wrap"><table><thead><tr><th>Item</th><th>Total</th></tr></thead><tbody><?php foreach ($rows as $row): ?><tr><td><?= htmlspecialchars($row['label'] ?: 'Sem rótulo') ?></td><td><?= (int) $row['total'] ?></td></tr><?php endforeach; ?><?php if (!$rows): ?><tr><td colspan="2">Sem dados.</td></tr><?php endif; ?></tbody></table></div></section><?php endforeach; ?></div>
